import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useCart } from '../../context/CartContext';
import api from '../../api/api';
import '../../assets/styles/Collection.css';

const Collection = () => {
  const { addToCart } = useCart();
  const navigate = useNavigate();
  const [products, setProducts] = React.useState({});
  const [loading, setLoading] = React.useState(true);

  React.useEffect(() => {
    const fetchProducts = async () => {
      try {
        const data = await api.get('/api/products');
        if (data.success) {
          const map = {};
          data.products.forEach(p => {
            map[p.id] = {
              id: p.id,
              title: p.title,
              price: p.variants['500g']?.price || p.variants['1kg']?.price || 0,
              image: p.images[0],
              weight: p.variants['500g'] ? '500g' : '1kg'
            };
          });
          setProducts(map);
        }
      } catch (err) {
        console.error('Failed to fetch collection products', err);
      } finally {
        setLoading(false);
      }
    };
    fetchProducts();
  }, []);

  const handleQuickAdd = async (e, key) => {
    e.preventDefault();
    e.stopPropagation();
    const product = products[key];
    if (!product) return;
    await addToCart({
      productId: product.id,
      title: product.title,
      price: product.price,
      image: product.image,
      weight: product.weight,
      quantity: 1
    });
  };

  const handleBuyNow = async (e, key) => {
    e.preventDefault();
    e.stopPropagation();
    const product = products[key];
    if (!product) return;
    await addToCart({
      productId: product.id,
      title: product.title,
      price: product.price,
      image: product.image,
      weight: product.weight,
      quantity: 1
    }, false);
    navigate('/checkout');
  };

  if (loading) return null; // Or a subtle loader
  if (Object.keys(products).length === 0) return null;

  return (
    <section className="collection-section">
      <div className="collection-header">
        <h2 className="collection-title">The Atelier Collection</h2>
        <div className="collection-divider"></div>
      </div>

      <div className="collection-grid">
        {/* Large Card Layout */}
        <Link to={`/product/desi-ghee`} className="collection-card card-large" style={{ textDecoration: 'none' }}>
          <img src={products['desi-ghee']?.image || "/images/desi-ghee.png"} alt={products['desi-ghee']?.title || "Desi Ghee"} className="collection-img" />
          <div className="collection-text-overlay">
            <div className="overlay-info">
              <h3>{products['desi-ghee']?.title || 'Sona Desi Ghee'}</h3>
              <p>From happy A2 cows</p>
            </div>
            <div className="overlay-actions">
              <button className="coll-btn-cart" onClick={(e) => handleQuickAdd(e, 'desi-ghee')}>+ Cart</button>
              <button className="coll-btn-buy" onClick={(e) => handleBuyNow(e, 'desi-ghee')}>Buy Now</button>
            </div>
          </div>
        </Link>

        {/* Small Cards */}
        <Link to="/product/kaju-amritan" className="collection-card kaju" style={{ textDecoration: 'none' }}>
          <img src={products['kaju-amritan']?.image || "/images/kaju-amritan.png"} alt={products['kaju-amritan']?.title || "Kaju Amritan"} className="collection-img" />
          <div className="collection-text-overlay">
            <div className="overlay-info">
              <h3>{products['kaju-amritan']?.title || 'Kaju Amritan'}</h3>
              <p>Rich & Nutty</p>
            </div>
            <div className="overlay-actions">
              <button className="coll-btn-cart" onClick={(e) => handleQuickAdd(e, 'kaju-amritan')}>+ Cart</button>
              <button className="coll-btn-buy" onClick={(e) => handleBuyNow(e, 'kaju-amritan')}>Buy Now</button>
            </div>
          </div>
        </Link>

        <Link to="/product/desi-gud" className="collection-card gud" style={{ textDecoration: 'none' }}>
          <img src={products['desi-gud']?.image || "/images/desi-gud.png"} alt={products['desi-gud']?.title || "Desi Gud"} className="collection-img" />
          <div className="collection-text-overlay">
            <div className="overlay-info">
              <h3>{products['desi-gud']?.title || 'Desi Gud'}</h3>
              <p>Pure Sugarcane</p>
            </div>
            <div className="overlay-actions">
              <button className="coll-btn-cart" onClick={(e) => handleQuickAdd(e, 'desi-gud')}>+ Cart</button>
              <button className="coll-btn-buy" onClick={(e) => handleBuyNow(e, 'desi-gud')}>Buy Now</button>
            </div>
          </div>
        </Link>

        {/* Wide Card Layout */}
        <Link to="/product/amritan-powder" className="collection-card card-wide" style={{ textDecoration: 'none' }}>
          <img src={products['amritan-powder']?.image || "/images/amritan-powder.png"} alt={products['amritan-powder']?.title || "Amritan Powder"} className="collection-img" />
          <div className="collection-text-overlay">
            <div className="overlay-info">
              <h3>{products['amritan-powder']?.title || 'Amritan Powder'}</h3>
              <p>Fine texture alternative</p>
            </div>
            <div className="overlay-actions">
              <button className="coll-btn-cart" onClick={(e) => handleQuickAdd(e, 'amritan-powder')}>+ Cart</button>
              <button className="coll-btn-buy" onClick={(e) => handleBuyNow(e, 'amritan-powder')}>Buy Now</button>
            </div>
          </div>
        </Link>
      </div>
    </section>
  );
};

export default React.memo(Collection);
